// --- Modals ---

const AddTaskModal = ({ isOpen, onClose, onSave, initialTask }: { isOpen: boolean, onClose: () => void, onSave: (task: IdentityTask) => void, initialTask?: IdentityTask | null }) => {
    if (!isOpen) return null;
    const [text, setText] = useState('');
    const [type, setType] = useState<'boolean' | 'measurable'>('boolean');
    const [target, setTarget] = useState(1);
    const [unit, setUnit] = useState('');
    const [selectedIcon, setSelectedIcon] = useState('star');

    useEffect(() => {
        if (initialTask) {
            setText(initialTask.text);
            setType(initialTask.type);
            setTarget(initialTask.target || 1);
            setUnit(initialTask.unit || '');
            setSelectedIcon(initialTask.icon || 'star');
        } else {
            setText('');
            setType('boolean');
            setTarget(1);
            setUnit('');
            setSelectedIcon('star');
        }
    }, [initialTask, isOpen]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave({
            id: initialTask ? initialTask.id : Date.now().toString(),
            text,
            type,
            completed: initialTask ? initialTask.completed : false,
            target: type === 'measurable' ? target : undefined,
            // Preserve current progress if editing same type, otherwise reset
            current: (initialTask && initialTask.type === type) ? initialTask.current : (type === 'measurable' ? 0 : undefined),
            unit: type === 'measurable' ? unit : undefined,
            icon: selectedIcon
        });
        onClose();
        if (!initialTask) {
            setText('');
            setTarget(1);
            setUnit('');
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm">
            <div className="glass-card w-full max-w-md p-6 rounded-2xl animate-fade-in-up">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xl font-bold text-slate-900 dark:text-white">{initialTask ? 'Edit Habit' : 'Add New Habit'}</h3>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-white/10 rounded-full"><XMarkIcon className="w-5 h-5" /></button>
                </div>
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium mb-1 text-slate-700 dark:text-slate-300">Habit Name</label>
                        <input type="text" required value={text} onChange={e => setText(e.target.value)} className="w-full p-3 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-violet-500 outline-none" placeholder="e.g. Read 10 pages" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium mb-1 text-slate-700 dark:text-slate-300">Type</label>
                        <div className="flex gap-2">
                            <button type="button" onClick={() => setType('boolean')} className={`flex-1 p-2 rounded-lg border ${type === 'boolean' ? 'bg-violet-500 text-white border-violet-500' : 'border-slate-200 dark:border-slate-700 text-slate-500'}`}>Checklist</button>
                            <button type="button" onClick={() => setType('measurable')} className={`flex-1 p-2 rounded-lg border ${type === 'measurable' ? 'bg-violet-500 text-white border-violet-500' : 'border-slate-200 dark:border-slate-700 text-slate-500'}`}>Counter</button>
                        </div>
                    </div>
                    {type === 'measurable' && (
                        <div className="flex gap-4">
                            <div className="flex-1">
                                <label className="block text-sm font-medium mb-1 text-slate-700 dark:text-slate-300">Target</label>
                                <input type="number" min="1" value={target} onChange={e => setTarget(parseInt(e.target.value))} className="w-full p-3 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 outline-none" />
                            </div>
                            <div className="flex-1">
                                <label className="block text-sm font-medium mb-1 text-slate-700 dark:text-slate-300">Unit</label>
                                <input type="text" value={unit} onChange={e => setUnit(e.target.value)} className="w-full p-3 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 outline-none" placeholder="e.g. mins" />
                            </div>
                        </div>
                    )}
                    <div>
                         <label className="block text-sm font-medium mb-2 text-slate-700 dark:text-slate-300">Icon</label>
                         <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                             {Object.keys(TASK_ICONS).map(key => {
                                 const Icon = TASK_ICONS[key];
                                 return (
                                     <button key={key} type="button" onClick={() => setSelectedIcon(key)} className={`p-2 rounded-lg border flex-shrink-0 ${selectedIcon === key ? 'bg-violet-500 text-white border-violet-500' : 'border-slate-200 dark:border-slate-700 text-slate-400'}`}>
                                         <Icon className="w-5 h-5" />
                                     </button>
                                 )
                             })}
                         </div>
                    </div>
                    <button type="submit" className="w-full py-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-xl font-bold hover:opacity-90 transition-opacity">{initialTask ? 'Save Changes' : 'Add Habit'}</button>
                </form>
            </div>
        </div>
    );
}

const DeleteTaskModal = ({ isOpen, onClose, onConfirm, taskName }: { isOpen: boolean, onClose: () => void, onConfirm: () => void, taskName: string }) => {
    useEffect(() => {
        if (!isOpen) return;
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
            if (e.key === 'Enter') onConfirm();
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [isOpen, onClose, onConfirm]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
            <div 
                className="glass-card w-full max-w-sm p-6 rounded-2xl animate-scale-in border-l-4 border-red-500 shadow-2xl relative"
                onClick={(e) => e.stopPropagation()}
            >
                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Delete Habit?</h3>
                <p className="text-slate-600 dark:text-slate-300 mb-6 leading-relaxed">
                    Are you sure you want to delete <span className="font-bold text-slate-900 dark:text-white">"{taskName}"</span>? This action cannot be undone.
                </p>
                <div className="flex gap-3 justify-end">
                    <button 
                        onClick={onClose} 
                        className="px-4 py-2 text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white font-medium transition-colors"
                    >
                        Cancel
                    </button>
                    <button 
                        onClick={onConfirm} 
                        className="px-6 py-2 bg-red-500 hover:bg-red-600 text-white rounded-lg font-bold shadow-lg shadow-red-500/20 transition-all hover:scale-105 active:scale-95"
                    >
                        Delete
                    </button>
                </div>
            </div>
        </div>
    );
}

const AddIdentityModal = ({ 
    isOpen, 
    onClose, 
    onAddPreset, 
    onCreateCustom, 
    availablePresets 
}: { 
    isOpen: boolean, 
    onClose: () => void, 
    onAddPreset: (id: string) => void, 
    onCreateCustom: (identity: Identity) => void,
    availablePresets: Identity[] 
}) => {
    if(!isOpen) return null;
    const [view, setView] = useState<'presets' | 'custom'>('presets');
    const [name, setName] = useState('');
    const [desc, setDesc] = useState('');
    const [selectedPresetId, setSelectedPresetId] = useState(THEME_PRESETS[0].id);

    // If no presets available, switch to custom view by default
    useEffect(() => {
        if (availablePresets.length === 0 && view === 'presets') {
            setView('custom');
        }
    }, [availablePresets, view]);

    const handleCustomSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        const preset = THEME_PRESETS.find(p => p.id === selectedPresetId) || THEME_PRESETS[0];
        const newIdentity: Identity = {
            id: `custom-${Date.now()}`,
            name,
            description: desc,
            quote: "Your custom journey begins today.",
            author: "You",
            dailyProgress: {},
            identityTasks: {}, // Will be initialized empty
            theme: {
                gradient: preset.gradient,
                accentColor: preset.accentColor,
                icon: preset.icon
            }
        };
        onCreateCustom(newIdentity);
        onClose();
        setName('');
        setDesc('');
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-md">
            <div className="glass-card w-full max-w-3xl p-8 rounded-3xl animate-fade-in-up max-h-[90vh] overflow-y-auto">
                 <div className="flex justify-between items-center mb-6">
                    <div>
                        <h3 className="text-2xl font-bold text-slate-900 dark:text-white">Add Identity</h3>
                        <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">Choose a path or create your own.</p>
