const AddGoalModal = ({ isOpen, onClose, onAdd, ai }: { isOpen: boolean, onClose: () => void, onAdd: (goal: Goal) => void, ai: GoogleGenAI }) => {
    if (!isOpen) return null;
    const [title, setTitle] = useState('');
    const [category, setCategory] = useState<Goal['category']>('Personal');
    const [isThinking, setIsThinking] = useState(false);

    const handleSuggest = async () => {
        setIsThinking(true);
        try {
            const prompt = `Suggest a clear, specific, and actionable goal for someone focusing on ${category}. Return JSON: { "title": "Goal Title", "milestones": ["Milestone 1", "Milestone 2"] }`;
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: { responseMimeType: 'application/json' }
            });
            const text = response.text;
            if (text) {
                const data = JSON.parse(text);
                setTitle(data.title);
                // In a real app we'd populate milestones too, but for now simple title
            }
        } catch (e) {
            console.error(e);
        } finally {
            setIsThinking(false);
        }
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onAdd({
            id: Date.now().toString(),
            title,
            category,
            progress: 0,
            milestones: []
        });
        onClose();
        setTitle('');
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
            <div className="glass-card w-full max-w-md p-6 rounded-2xl animate-fade-in-up">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xl font-bold text-slate-900 dark:text-white">New Goal</h3>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-white/10 rounded-full"><XMarkIcon className="w-5 h-5" /></button>
                </div>
                <div className="mb-4">
                     <label className="block text-sm font-medium mb-2 text-slate-700 dark:text-slate-300">Category</label>
                     <div className="flex gap-2">
                        {['Health', 'Business', 'Personal', 'Financial'].map(cat => (
                            <button key={cat} onClick={() => setCategory(cat as any)} className={`px-3 py-1 rounded-full text-xs font-bold border transition-colors ${category === cat ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900 border-transparent' : 'text-slate-500 border-slate-200 dark:border-slate-700'}`}>
                                {cat}
                            </button>
                        ))}
                     </div>
                </div>
                <form onSubmit={handleSubmit} className="space-y-4">
                     <div>
                        <label className="block text-sm font-medium mb-1 text-slate-700 dark:text-slate-300">Goal Title</label>
                        <div className="relative">
                            <input type="text" required value={title} onChange={e => setTitle(e.target.value)} className="w-full p-3 pr-10 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 focus:ring-2 focus:ring-violet-500 outline-none" placeholder="e.g. Save $5,000" />
                            <button type="button" onClick={handleSuggest} disabled={isThinking} className="absolute right-2 top-2 p-1.5 text-violet-500 hover:bg-violet-500/10 rounded-lg" title="AI Suggestion">
                                {isThinking ? <span className="animate-spin block">✨</span> : <SparklesIcon className="w-5 h-5" />}
                            </button>
                        </div>
                    </div>
                    <button type="submit" className="w-full py-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-xl font-bold hover:opacity-90 transition-opacity">Set Goal</button>
                </form>
            </div>
        </div>
    );
};

