                             <div className="mb-6">
                                <label className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-3 block">How are you feeling?</label>
                                <div className="flex justify-between gap-2">
                                    {MOODS.map((m) => (
                                        <button
                                            key={m.value}
