// --- Interfaces ---

interface IdentityTask {
    id: string;
    text: string;
    type: 'boolean' | 'measurable';
    completed: boolean;
    target?: number;
    current?: number;
    unit?: string;
    icon?: string; 
}

interface Identity {
    id: string;
    name: string;
    description: string;
    quote: string;
    author: string;
    identityTasks: { [key: string]: IdentityTask[] }; // tasks per identity ID
    dailyProgress: { [date: string]: number };
    theme?: {
        gradient: string;
        accentColor: string;
        icon: string;
    };
}

interface User {
    name: string;
}

interface Goal {
    id: string;
    title: string;
    category: 'Health' | 'Business' | 'Personal' | 'Financial';
    progress: number;
    milestones: { text: string; completed: boolean }[];
    aiSuggested?: boolean;
}

interface DailyWin {
    id: string;
    category: 'physical' | 'mental' | 'spiritual';
    text: string;
    completed: boolean;
}

interface DailyData {
    date: string;
    wins: DailyWin[];
    reflection: string;
    mood: number; // 1-5
    questionAnswer: string;
    question: string;
}

interface UserData {
    theme: 'light' | 'dark';
    isOnboardingComplete?: boolean;
    identity: Identity; // The currently ACTIVE identity
    unlockedIdentityIds: string[]; // IDs of DEFAULT_IDENTITIES that the user has added
    goals: Goal[];
    history: DailyData[];
    todayDraft?: DailyData; // Persist today's unsaved progress
    streak: number;
    totalWins: number;
    customIdentities: Identity[]; // User created identities
    achievements: string[];
    dailyAffirmation?: { text: string; date: string };
}

interface Achievement {
    id: string;
    title: string;
    description: string;
    icon: any;
    condition: (data: UserData) => boolean;
}

interface PresetHabit {
    text: string;
    type: 'boolean' | 'measurable';
    target?: number;
    unit?: string;
    icon: string;
    identityIds: string[]; // Ties habits to specific identities
}

