interface IdentityTask {
    id: string;
    text: string;
    type: 'boolean' | 'measurable';
    completed: boolean;
    target?: number;
    current?: number;
    unit?: string;
    icon?: string; 
}

interface Identity {
    id: string;
    name: string;
    description: string;
    quote: string;
    author: string;
    identityTasks: { [key: string]: IdentityTask[] }; // tasks per identity ID
