const AddTaskModal = ({ 
    isOpen, 
    onClose, 
    onSave, 
    initialTask,
    activeIdentity
}: { 
    isOpen: boolean, 
    onClose: () => void, 
    onSave: (task: IdentityTask) => void, 
    initialTask?: IdentityTask | null,
    activeIdentity: Identity
}) => {
    const [view, setView] = useState<'selection' | 'form'>(initialTask ? 'form' : 'selection');
    const [text, setText] = useState('');
    const [type, setType] = useState<'boolean' | 'measurable'>('boolean');
    const [target, setTarget] = useState(1);
    const [unit, setUnit] = useState('');
    const [selectedIcon, setSelectedIcon] = useState('star');

    // Filter presets to only those relevant to the current identity
    const relevantPresets = useMemo(() => {
        return PRESET_HABITS.filter(preset => preset.identityIds.includes(activeIdentity.id));
    }, [activeIdentity.id]);

    useEffect(() => {
        if (initialTask) {
            setText(initialTask.text);
            setType(initialTask.type);
            setTarget(initialTask.target || 1);
            setUnit(initialTask.unit || '');
            setSelectedIcon(initialTask.icon || 'star');
            setView('form');
        } else {
            setText('');
            setType('boolean');
            setTarget(1);
            setUnit('');
            setSelectedIcon('star');
            setView('selection');
        }
    }, [initialTask, isOpen]);

    if (!isOpen) return null;

    const handleSelectPreset = (preset: PresetHabit) => {
        setText(preset.text);
        setType(preset.type);
        setTarget(preset.target || 1);
        setUnit(preset.unit || '');
        setSelectedIcon(preset.icon);
        setView('form');
    };

    const handleCustom = () => {
        setView('form');
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave({
            id: initialTask ? initialTask.id : Date.now().toString(),
            text,
            type,
            completed: initialTask ? initialTask.completed : false,
            target: type === 'measurable' ? target : undefined,
            current: (initialTask && initialTask.type === type) ? initialTask.current : (type === 'measurable' ? 0 : undefined),
            unit: type === 'measurable' ? unit : undefined,
            icon: selectedIcon
        });
        onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="glass-card w-full max-w-2xl rounded-3xl animate-fade-in-up overflow-hidden flex flex-col max-h-[85vh]">
                <div className="p-6 border-b border-slate-200 dark:border-white/10 flex justify-between items-center bg-white/50 dark:bg-black/20">
                    <div>
                        <h3 className="text-2xl font-black text-slate-900 dark:text-white">
                            {view === 'selection' ? 'Discover New Habits' : (initialTask ? 'Edit Habit' : 'Customize Habit')}
                        </h3>
                        {view === 'selection' && (
                            <p className="text-sm text-slate-500 font-medium mt-0.5">Recommendations for {activeIdentity.name}</p>
                        )}
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-white/10 rounded-full transition-colors"><XMarkIcon className="w-6 h-6" /></button>
                </div>

                <div className="flex-1 overflow-y-auto p-6 space-y-6">
                    {view === 'selection' ? (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <button 
                                    onClick={handleCustom}
                                    className="p-6 rounded-2xl border-2 border-dashed border-slate-200 dark:border-white/10 hover:border-violet-500/50 hover:bg-violet-500/5 transition-all flex flex-col items-center justify-center gap-3 group text-slate-500 hover:text-violet-500 bg-white/40 dark:bg-black/10"
                                >
                                    <div className="w-12 h-12 rounded-full flex items-center justify-center bg-slate-100 dark:bg-white/5 group-hover:bg-violet-500 group-hover:text-white transition-all">
                                        <PlusIcon className="w-7 h-7" />
                                    </div>
                                    <span className="font-bold text-base">Custom Habit</span>
                                </button>
                                {relevantPresets.length > 0 ? (
                                    relevantPresets.map((preset, idx) => {
                                        const Icon = TASK_ICONS[preset.icon] || SparklesIcon;
                                        return (
                                            <button 
                                                key={idx}
                                                onClick={() => handleSelectPreset(preset)}
                                                className="text-left p-6 rounded-2xl border border-slate-200 dark:border-white/10 bg-white/60 dark:bg-white/5 hover:bg-white dark:hover:bg-white/10 hover:border-violet-500/30 hover:shadow-xl transition-all flex items-start gap-4 group"
                                            >
                                                <div className="p-3.5 rounded-xl bg-violet-500/10 text-violet-500 group-hover:bg-violet-500 group-hover:text-white transition-all duration-300">
                                                    <Icon className="w-6 h-6" />
                                                </div>
                                                <div className="flex-1 pt-0.5">
                                                    <h4 className="font-bold text-slate-900 dark:text-white leading-tight text-lg mb-1">{preset.text}</h4>
                                                    <p className="text-sm font-medium text-slate-400 group-hover:text-slate-500 transition-colors">
                                                        {preset.type === 'boolean' ? 'Checklist' : `Goal: ${preset.target} ${preset.unit}`}
                                                    </p>
                                                </div>
                                            </button>
                                        );
                                    })
                                ) : (
                                    <div className="col-span-full py-10 text-center">
                                        <p className="text-slate-500 font-medium">No specific presets for this identity yet.</p>
                                        <p className="text-slate-400 text-sm mt-1">Try creating a custom one above!</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    ) : (
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="flex gap-4">
                                <button 
                                    type="button" 
                                    onClick={() => setView('selection')} 
                                    className={`px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 border border-slate-200 dark:border-white/10 text-slate-500 hover:text-slate-900 dark:hover:text-white transition-colors ${initialTask ? 'hidden' : ''}`}
                                >
                                    ← Back to recommendations
                                </button>
                            </div>

                            <div className="space-y-4">
                                <div>
                                    <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">Habit Name</label>
                                    <input type="text" required value={text} onChange={e => setText(e.target.value)} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 focus:ring-4 focus:ring-violet-500/20 outline-none text-lg font-medium" placeholder="e.g. Read 10 pages" />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">Tracking Type</label>
                                        <div className="flex p-1 bg-slate-100 dark:bg-white/5 rounded-xl border border-slate-200 dark:border-white/5">
                                            <button type="button" onClick={() => setType('boolean')} className={`flex-1 py-3 rounded-lg font-bold text-sm transition-all ${type === 'boolean' ? 'bg-white dark:bg-white/10 shadow-lg text-violet-500' : 'text-slate-400'}`}>Simple</button>
                                            <button type="button" onClick={() => setType('measurable')} className={`flex-1 py-3 rounded-lg font-bold text-sm transition-all ${type === 'measurable' ? 'bg-white dark:bg-white/10 shadow-lg text-violet-500' : 'text-slate-400'}`}>Target</button>
                                        </div>
                                    </div>
                                    <div className={`transition-all duration-300 ${type === 'measurable' ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}>
                                        <div className="flex gap-2">
                                            <div className="flex-1">
                                                <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">Target</label>
                                                <input type="number" min="1" value={target} onChange={e => setTarget(parseInt(e.target.value))} className="w-full p-3 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 outline-none" />
                                            </div>
                                            <div className="flex-1">
                                                <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">Unit</label>
                                                <input type="text" value={unit} onChange={e => setUnit(e.target.value)} className="w-full p-3 rounded-xl bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 outline-none" placeholder="pgs" />
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-3">Choose an Icon</label>
                                    <div className="flex gap-3 overflow-x-auto pb-4 no-scrollbar">
                                        {Object.keys(TASK_ICONS).map(key => {
                                            const Icon = TASK_ICONS[key];
                                            return (
                                                <button key={key} type="button" onClick={() => setSelectedIcon(key)} className={`w-14 h-14 rounded-2xl border-2 flex-shrink-0 flex items-center justify-center transition-all ${selectedIcon === key ? 'bg-violet-500 text-white border-violet-500 shadow-xl shadow-violet-500/30' : 'border-slate-200 dark:border-white/10 text-slate-400 hover:bg-slate-50 dark:hover:bg-white/5'}`}>
                                                    <Icon className="w-7 h-7" />
                                                </button>
                                            )
                                        })}
                                    </div>
                                </div>
                            </div>

                            <button type="submit" className="w-full py-5 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-2xl font-black text-xl hover:opacity-90 transition-all active:scale-[0.98] shadow-2xl">
                                {initialTask ? 'Save Changes' : 'Create Habit'}
                            </button>
                        </form>
                    )}
                </div>
            </div>
        </div>
    );
}

const DeleteTaskModal = ({ isOpen, onClose, onConfirm, taskName }: { isOpen: boolean, onClose: () => void, onConfirm: () => void, taskName: string }) => {
    useEffect(() => {
        if (!isOpen) return;
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
            if (e.key === 'Enter') onConfirm();
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [isOpen, onClose, onConfirm]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
            <div 
                className="glass-card w-full max-sm p-6 rounded-2xl animate-scale-in border-l-4 border-red-500 shadow-2xl relative"
                onClick={(e) => e.stopPropagation()}
            >
                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Delete Habit?</h3>
                <p className="text-slate-600 dark:text-slate-300 mb-6 leading-relaxed">
                    Are you sure you want to delete <span className="font-bold text-slate-900 dark:text-white">"{taskName}"</span>? This action cannot be undone.
                </p>
                <div className="flex gap-3 justify-end">
                    <button 
                        onClick={onClose} 
                        className="px-4 py-2 text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white font-medium transition-colors"
                    >
                        Cancel
                    </button>
                    <button 
                        onClick={onConfirm} 
                        className="px-6 py-2 bg-red-500 hover:bg-red-600 text-white rounded-lg font-bold shadow-lg shadow-red-500/20 transition-all hover:scale-105 active:scale-95"
                    >
                        Delete
                    </button>
                </div>
            </div>
        </div>
    );
}

