const AddTaskModal = ({ 
    isOpen, 
    onClose, 
    onSave, 
    initialTask,
    activeIdentity
}: { 
    isOpen: boolean, 
    onClose: () => void, 
    onSave: (task: IdentityTask) => void, 
    initialTask?: IdentityTask | null,
    activeIdentity: Identity
}) => {
    const [text, setText] = useState('');
    const [type, setType] = useState<'boolean' | 'measurable'>('boolean');
    const [target, setTarget] = useState(1);
    const [unit, setUnit] = useState('');
    const [selectedIcon, setSelectedIcon] = useState('star');

    const relevantPresets = useMemo(() => {
        return PRESET_HABITS.filter(preset => preset.identityIds.includes(activeIdentity.id));
    }, [activeIdentity.id]);

    useEffect(() => {
        if (initialTask) {
            setText(initialTask.text);
            setType(initialTask.type);
            setTarget(initialTask.target || 1);
            setUnit(initialTask.unit || '');
            setSelectedIcon(initialTask.icon || 'star');
        } else {
            setText('');
            setType('boolean');
            setTarget(1);
            setUnit('');
            setSelectedIcon('star');
        }
    }, [initialTask, isOpen]);

    if (!isOpen) return null;

    const handleSelectPreset = (preset: PresetHabit) => {
        setText(preset.text);
        setType(preset.type);
        setTarget(preset.target || 1);
        setUnit(preset.unit || '');
        setSelectedIcon(preset.icon);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave({
            id: initialTask ? initialTask.id : Date.now().toString(),
            text,
            type,
            completed: initialTask ? initialTask.completed : false,
            target: type === 'measurable' ? target : undefined,
            current: (initialTask && initialTask.type === type) ? initialTask.current : (type === 'measurable' ? 0 : undefined),
            unit: type === 'measurable' ? unit : undefined,
            icon: selectedIcon
        });
        onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="glass-card w-full max-w-5xl rounded-3xl animate-fade-in-up overflow-hidden flex flex-col max-h-[90vh]">
                {/* Modal Header */}
                <div className="p-6 border-b border-slate-200 dark:border-white/10 flex justify-between items-center bg-white/50 dark:bg-black/20">
                    <div>
                        <h3 className="text-2xl font-black text-slate-900 dark:text-white">
                            {initialTask ? 'Edit Habit' : 'Choose Your Next Win'}
                        </h3>
                        <p className="text-sm text-slate-500 font-medium mt-0.5">Focusing on: {activeIdentity.name}</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-white/10 rounded-full transition-colors"><XMarkIcon className="w-6 h-6" /></button>
                </div>

                {/* Content Split */}
                <div className="flex flex-col lg:flex-row flex-1 overflow-hidden">

                    {/* Left Side: Preset Library */}
                    <div className="w-full lg:w-1/2 border-r border-slate-200 dark:border-white/10 bg-slate-50/30 dark:bg-black/10 overflow-y-auto p-6 space-y-4 no-scrollbar">
                        <div className="flex items-center gap-2 mb-4">
                            <SparklesIcon className="w-4 h-4 text-violet-500" />
                            <h4 className="text-xs font-black uppercase tracking-widest text-slate-400">Identity Library</h4>
                        </div>
                        <div className="grid grid-cols-1 gap-3">
                            {relevantPresets.length > 0 ? (
                                relevantPresets.map((preset, idx) => {
                                    const Icon = TASK_ICONS[preset.icon] || SparklesIcon;
                                    const isActive = text === preset.text;
                                    return (
                                        <button 
                                            key={idx}
                                            onClick={() => handleSelectPreset(preset)}
                                            className={`text-left p-4 rounded-2xl border transition-all flex items-center gap-4 group ${isActive ? 'bg-violet-500 border-violet-500 shadow-xl shadow-violet-500/20' : 'bg-white dark:bg-white/5 border-slate-200 dark:border-white/5 hover:border-violet-500/30 hover:bg-slate-50 dark:hover:bg-white/10'}`}
                                        >
                                            <div className={`p-2.5 rounded-xl transition-all ${isActive ? 'bg-white text-violet-500' : 'bg-violet-500/10 text-violet-500 group-hover:bg-violet-500 group-hover:text-white'}`}>
                                                <Icon className="w-5 h-5" />
                                            </div>
                                            <div className="flex-1">
                                                <h5 className={`font-bold leading-tight ${isActive ? 'text-white' : 'text-slate-900 dark:text-white'}`}>{preset.text}</h5>
                                                <p className={`text-xs mt-0.5 ${isActive ? 'text-violet-100' : 'text-slate-400'}`}>
                                                    {preset.type === 'boolean' ? 'One-time daily' : `${preset.target} ${preset.unit} goal`}
