                                            </div>
                                            <ArrowRightIcon className={`w-4 h-4 transition-all ${isActive ? 'text-white opacity-100' : 'opacity-0 -translate-x-2 group-hover:opacity-100 group-hover:translate-x-0 text-violet-500'}`} />
                                        </button>
                                    );
                                })
                            ) : (
                                <div className="py-12 text-center">
                                    <p className="text-slate-500 font-medium italic">Custom identity: no presets available.</p>
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Right Side: Custom Creation Form */}
                    <div className="w-full lg:w-1/2 overflow-y-auto p-8 bg-white dark:bg-slate-900/20 no-scrollbar">
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="flex items-center gap-2 mb-4">
                                <PencilIcon className="w-4 h-4 text-violet-500" />
                                <h4 className="text-xs font-black uppercase tracking-widest text-slate-400">Configure Habit</h4>
                            </div>

                            <div className="space-y-6">
                                <div>
                                    <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">Habit Name</label>
                                    <input 
                                        type="text" 
                                        required 
                                        value={text} 
                                        onChange={e => setText(e.target.value)} 
                                        className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-black/20 border border-slate-200 dark:border-slate-700 focus:ring-4 focus:ring-violet-500/20 outline-none text-lg font-bold" 
                                        placeholder="Enter habit name..." 
                                    />
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">Tracking Type</label>
                                        <div className="flex p-1 bg-slate-100 dark:bg-white/5 rounded-xl border border-slate-200 dark:border-white/5">
                                            <button type="button" onClick={() => setType('boolean')} className={`flex-1 py-3 rounded-lg font-bold text-sm transition-all ${type === 'boolean' ? 'bg-white dark:bg-white/10 shadow-lg text-violet-500' : 'text-slate-400'}`}>Simple</button>
                                            <button type="button" onClick={() => setType('measurable')} className={`flex-1 py-3 rounded-lg font-bold text-sm transition-all ${type === 'measurable' ? 'bg-white dark:bg-white/10 shadow-lg text-violet-500' : 'text-slate-400'}`}>Target</button>
                                        </div>
                                    </div>
                                    {type === 'measurable' && (
                                        <div className="animate-fade-in-up">
                                            <div className="flex gap-2">
                                                <div className="flex-1">
                                                    <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">Target</label>
                                                    <input type="number" min="1" value={target} onChange={e => setTarget(parseInt(e.target.value))} className="w-full p-3 rounded-xl bg-slate-50 dark:bg-black/20 border border-slate-200 dark:border-slate-700 outline-none font-bold" />
                                                </div>
                                                <div className="flex-1">
                                                    <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2">Unit</label>
                                                    <input type="text" value={unit} onChange={e => setUnit(e.target.value)} className="w-full p-3 rounded-xl bg-slate-50 dark:bg-black/20 border border-slate-200 dark:border-slate-700 outline-none font-bold" placeholder="e.g. L, pg" />
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>

                                <div>
                                    <label className="block text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-3">Habit Icon</label>
                                    <div className="grid grid-cols-5 md:grid-cols-6 gap-2 h-32 overflow-y-auto no-scrollbar border-y border-slate-100 dark:border-white/5 py-3">
                                        {Object.keys(TASK_ICONS).map(key => {
                                            const Icon = TASK_ICONS[key];
                                            return (
                                                <button key={key} type="button" onClick={() => setSelectedIcon(key)} className={`aspect-square rounded-xl border flex items-center justify-center transition-all ${selectedIcon === key ? 'bg-violet-500 text-white border-violet-500 shadow-lg shadow-violet-500/20' : 'border-slate-100 dark:border-white/5 text-slate-400 hover:bg-slate-50 dark:hover:bg-white/5'}`}>
                                                    <Icon className="w-5 h-5" />
                                                </button>
                                            )
                                        })}
                                    </div>
                                </div>
                            </div>

                            <button type="submit" className="w-full py-5 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-2xl font-black text-xl hover:opacity-90 transition-all active:scale-[0.98] shadow-2xl mt-4">
                                {initialTask ? 'Save Changes' : 'Confirm Habit'}
                            </button>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    );
}

const DeleteTaskModal = ({ isOpen, onClose, onConfirm, taskName }: { isOpen: boolean, onClose: () => void, onConfirm: () => void, taskName: string }) => {
    useEffect(() => {
        if (!isOpen) return;
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
            if (e.key === 'Enter') onConfirm();
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [isOpen, onClose, onConfirm]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fade-in">
            <div className="glass-card w-full max-sm p-6 rounded-2xl animate-scale-in border-l-4 border-red-500 shadow-2xl relative">
                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Delete Habit?</h3>
                <p className="text-slate-600 dark:text-slate-300 mb-6 leading-relaxed">
                    Are you sure you want to delete <span className="font-bold text-slate-900 dark:text-white">"{taskName}"</span>?
                </p>
                <div className="flex gap-3 justify-end">
                    <button onClick={onClose} className="px-4 py-2 text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white font-medium transition-colors">Cancel</button>
                    <button onClick={onConfirm} className="px-6 py-2 bg-red-500 hover:bg-red-600 text-white rounded-lg font-bold shadow-lg transition-all active:scale-95">Delete</button>
                </div>
            </div>
        </div>
    );
}

