const AddGoalModal = ({ isOpen, onClose, onAdd, ai }: { isOpen: boolean, onClose: () => void, onAdd: (goal: Goal) => void, ai: GoogleGenAI }) => {
    if (!isOpen) return null;
    const [title, setTitle] = useState('');
    const [category, setCategory] = useState<Goal['category']>('Personal');
    const [isThinking, setIsThinking] = useState(false);
    const handleSuggest = async () => {
        setIsThinking(true);
        try {
            const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: `Suggest a goal for ${category}. Return JSON: { "title": "..." }`, config: { responseMimeType: 'application/json' } });
            if (response.text) setTitle(JSON.parse(response.text).title);
        } catch (e) {} finally { setIsThinking(false); }
    };
    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onAdd({ id: Date.now().toString(), title, category, progress: 0, milestones: [] });
        onClose();
    };
    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
            <div className="glass-card w-full max-w-md p-6 rounded-2xl animate-fade-in-up">
                <div className="flex justify-between items-center mb-6"><h3 className="text-xl font-bold">New Goal</h3><button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-white/10 rounded-full"><XMarkIcon className="w-5 h-5" /></button></div>
                <form onSubmit={handleSubmit} className="space-y-4">
                     <div className="flex gap-2 mb-4">{['Health', 'Business', 'Personal', 'Financial'].map(cat => <button key={cat} type="button" onClick={() => setCategory(cat as any)} className={`px-3 py-1 rounded-full text-xs font-bold border ${category === cat ? 'bg-slate-900 dark:bg-white text-white dark:text-slate-900' : 'text-slate-500 border-slate-200 dark:border-slate-700'}`}>{cat}</button>)}</div>
                     <div className="relative"><input type="text" required value={title} onChange={e => setTitle(e.target.value)} className="w-full p-3 pr-10 rounded-xl bg-slate-50 dark:bg-slate-900/50 border outline-none" /><button type="button" onClick={handleSuggest} disabled={isThinking} className="absolute right-2 top-2 p-1.5 text-violet-500">{isThinking ? '...' : <SparklesIcon className="w-5 h-5" />}</button></div>
                    <button type="submit" className="w-full py-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-xl font-bold">Set Goal</button>
                </form>
            </div>
        </div>
    );
};

