    const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
    const [taskToDelete, setTaskToDelete] = useState<{ id: string, name: string } | null>(null);
    const [editingTask, setEditingTask] = useState<IdentityTask | null>(null);
    const availablePresets = useMemo(() => {
        const myIds = myIdentities.map(i => i.id);
        return allPresets.filter(p => !myIds.includes(p.id));
    }, [allPresets, myIdentities]);
    const currentTheme = useMemo(() => identity.theme || DEFAULT_IDENTITIES.find(d => d.id === identity.id)?.theme || { gradient: THEMES.slate.gradient, accentColor: THEMES.slate.accentColor, icon: 'star' }, [identity]);
    const tasks = (identity.identityTasks && identity.identityTasks[identity.id]) ? identity.identityTasks[identity.id] : [];
    const handleTaskToggle = (taskId: string) => {
        onUpdate({ ...identity, identityTasks: { ...identity.identityTasks, [identity.id]: tasks.map(t => t.id === taskId ? { ...t, completed: !t.completed } : t) } });
    };
    const handleCounter = (taskId: string, delta: number) => {
        onUpdate({ ...identity, identityTasks: { ...identity.identityTasks, [identity.id]: tasks.map(t => {
            if (t.id === taskId && t.type === 'measurable') {
                const newCurrent = Math.max(0, (t.current || 0) + delta);
                return { ...t, current: newCurrent, completed: newCurrent >= (t.target || 1) };
            }
            return t;
        }) } });
    };
    const handleSaveTask = (task: IdentityTask) => {
        const exists = tasks.some(t => t.id === task.id);
        onUpdate({ ...identity, identityTasks: { ...identity.identityTasks, [identity.id]: exists ? tasks.map(t => t.id === task.id ? task : t) : [...tasks, task] } });
        setEditingTask(null);
    };
    const confirmDeleteTask = () => {
        if (taskToDelete) onUpdate({ ...identity, identityTasks: { ...identity.identityTasks, [identity.id]: tasks.filter(t => t.id !== taskToDelete.id) } });
        setTaskToDelete(null);
    };
    const progress = useMemo(() => tasks.length === 0 ? 0 : Math.round((tasks.filter(t => t.completed).length / tasks.length) * 100), [tasks]);

    return (
        <div className="relative min-h-full pb-20">
             <IdentityBackground />
             <div className="relative z-10 max-w-5xl mx-auto space-y-8 animate-fade-in-up p-4">
                <div className="flex flex-col md:flex-row justify-between items-end gap-6">
                    <div>
                        <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full bg-slate-100 dark:bg-white/10 border mb-4 ${currentTheme.accentColor}`}>
                            <span className={`relative flex h-2 w-2`}><span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${currentTheme.accentColor.replace('text-', 'bg-')}`}></span><span className={`relative inline-flex rounded-full h-2 w-2 ${currentTheme.accentColor.replace('text-', 'bg-')}`}></span></span>
                            <span className="text-xs font-bold uppercase tracking-wider">Active Identity</span>
                        </div>
                        <h1 className="text-5xl md:text-6xl font-black mb-4">I am <span className={`text-transparent bg-clip-text bg-gradient-to-r ${currentTheme.gradient}`}>{identity.name}</span></h1>
                        <p className="text-xl md:text-2xl text-slate-600 dark:text-slate-300 max-w-2xl leading-relaxed font-medium">{identity.description}</p>
                    </div>
                    <div className="flex gap-4 overflow-x-auto p-4 max-w-full no-scrollbar">
                        {myIdentities.map(id => {
                            const isActive = id.id === identity.id;
                            const theme = id.theme || DEFAULT_IDENTITIES.find(d => d.id === id.id)?.theme || { ...THEMES.slate, icon: 'star' };
                            const IconComp = TASK_ICONS[theme.icon] || SparklesIcon;
                            return (
                                <button key={id.id} onClick={() => onSelectIdentity(id.id)} className={`relative flex-shrink-0 w-20 h-20 rounded-2xl flex items-center justify-center transition-all ${isActive ? 'scale-110 shadow-2xl ring-2 ring-offset-2 ring-slate-400' : 'hover:scale-105'}`}>
                                    <div className={`absolute inset-0 rounded-2xl bg-gradient-to-br ${theme.gradient} ${isActive ? 'opacity-100' : 'opacity-10'}`}></div>
                                    <div className={`relative z-10 font-bold ${isActive ? 'text-white' : 'text-slate-500'}`}><IconComp className="w-8 h-8" /></div>
                                </button>
                            );
                        })}
                        <button onClick={() => setIsCreateModalOpen(true)} className="flex-shrink-0 w-20 h-20 rounded-2xl border-2 border-dashed border-slate-300 flex items-center justify-center text-slate-400"><PlusIcon className="w-8 h-8" /></button>
                    </div>
                </div>
                <div className="glass-card p-1 rounded-full relative overflow-hidden"><div className={`h-2 rounded-full bg-gradient-to-r ${currentTheme.gradient} transition-all duration-1000`} style={{ width: `${progress}%` }}></div></div>
                <div>
                     <div className="flex justify-between items-center mb-8"><h2 className="text-4xl font-extrabold">Today's Habits</h2><button onClick={() => { setEditingTask(null); setIsTaskModalOpen(true); }} className="flex items-center gap-2 px-4 py-2 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-lg font-bold shadow-lg"><PlusIcon className="w-4 h-4" /> <span>Add Habit</span></button></div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {tasks.map(task => {
                             const Icon = task.icon && TASK_ICONS[task.icon] ? TASK_ICONS[task.icon] : SparklesIcon;
                             return (
                                <div key={task.id} className="group relative p-6 rounded-3xl bg-white/90 dark:bg-slate-900/40 border border-white/50 backdrop-blur-2xl shadow-lg hover:shadow-2xl hover:-translate-y-1 transition-all overflow-hidden">
                                    <div className={`absolute bottom-0 left-0 w-full h-1.5 bg-gradient-to-r ${currentTheme.gradient} opacity-50`}></div>
                                    <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity"><button onClick={() => { setEditingTask(task); setIsTaskModalOpen(true); }} className="p-2 text-slate-400 hover:text-violet-500"><PencilIcon className="w-4 h-4" /></button><button onClick={() => setTaskToDelete({ id: task.id, name: task.text })} className="p-2 text-slate-400 hover:text-red-500"><TrashIcon className="w-4 h-4" /></button></div>
                                    <div className="flex items-start gap-5 relative z-10">
                                        <div className={`p-4 rounded-2xl bg-gradient-to-br ${currentTheme.gradient} text-white shadow-xl`}><Icon className="w-7 h-7" /></div>
                                        <div className="flex-1">
                                            <h3 className={`text-2xl font-bold mb-2 transition-all ${task.completed ? 'text-slate-400 line-through' : ''}`}>{task.text}</h3>
                                            {task.type === 'boolean' ? (
                                                <button onClick={() => handleTaskToggle(task.id)} className={`w-full py-4 rounded-2xl font-bold flex items-center justify-center gap-2 transition-all ${task.completed ? 'bg-green-500 text-white shadow-xl' : 'bg-slate-100 dark:bg-white/5'}`}>
                                                    {task.completed ? <><CheckCircleIconSolid className="w-6 h-6 animate-check-pop" /> Complete</> : 'Mark Complete'}
                                                </button>
                                            ) : (
                                                <div className="flex items-center gap-3">
                                                    <button onClick={() => handleCounter(task.id, -1)} className="w-12 h-12 flex items-center justify-center rounded-2xl bg-slate-100 dark:bg-white/10"><MinusIcon className="w-5 h-5" /></button>
                                                    <div className="flex-1 h-12 flex items-center justify-center bg-slate-50 dark:bg-black/20 rounded-2xl border"><span className="font-mono font-bold text-xl">{task.current} / {task.target} <span className="text-xs text-slate-400 font-sans">{task.unit}</span></span></div>
                                                     <button onClick={() => handleCounter(task.id, 1)} className="w-12 h-12 flex items-center justify-center rounded-2xl bg-slate-900 dark:bg-white text-white dark:text-slate-900"><PlusIcon className="w-5 h-5" /></button>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                             )
                        })}
                    </div>
                </div>
             </div>
             <AddTaskModal isOpen={isTaskModalOpen} onClose={() => setIsTaskModalOpen(false)} onSave={handleSaveTask} initialTask={editingTask} activeIdentity={identity} />
             <DeleteTaskModal isOpen={!!taskToDelete} onClose={() => setTaskToDelete(null)} onConfirm={confirmDeleteTask} taskName={taskToDelete?.name || ''} />
             <AddIdentityModal isOpen={isCreateModalOpen} onClose={() => setIsCreateModalOpen(false)} onCreateCustom={onCreateCustom} onAddPreset={onAddPreset} availablePresets={availablePresets} />
        </div>
    );
};

// --- Main App Component ---

const App: React.FC = () => {
    const ai = useMemo(() => new GoogleGenAI({ apiKey: process.env.API_KEY }), []);
    const [userData, setUserData] = useState<UserData>(() => {
        const saved = localStorage.getItem('atomic_identity_data_v1');
        return saved ? JSON.parse(saved) : { theme: 'dark', isOnboardingComplete: false, identity: DEFAULT_IDENTITIES[0], unlockedIdentityIds: [DEFAULT_IDENTITIES[0].id], goals: [], history: [], streak: 0, totalWins: 0, customIdentities: [], achievements: [] };
    });
    const [activeView, setActiveView] = useState<'identity' | 'goals' | 'achievements'>('identity');
    const [unlockedAchievement, setUnlockedAchievement] = useState<Achievement | null>(null);
    const [isAddGoalModalOpen, setIsAddGoalModalOpen] = useState(false);
    useEffect(() => { localStorage.setItem('atomic_identity_data_v1', JSON.stringify(userData)); }, [userData]);
    useEffect(() => {
        const newAchievement = MASTER_ACHIEVEMENTS.find(a => !userData.achievements.includes(a.id) && a.condition(userData));
        if (newAchievement) {
            setUserData(prev => ({ ...prev, achievements: [...prev.achievements, newAchievement.id] }));
            setUnlockedAchievement(newAchievement);
        }
    }, [userData]);
    const handleUpdateIdentity = (updated: Identity) => {
        setUserData(prev => {
            const isCustom = prev.customIdentities.some(ci => ci.id === updated.id);
            return { ...prev, identity: updated.id === prev.identity.id ? updated : prev.identity, customIdentities: isCustom ? prev.customIdentities.map(ci => ci.id === updated.id ? updated : ci) : prev.customIdentities };
        });
    };
    const handleSelectIdentity = (id: string) => {
        const found = [...DEFAULT_IDENTITIES, ...userData.customIdentities].find(i => i.id === id);
        if (found) setUserData(prev => ({ ...prev, identity: found }));
    };
    const handleCreateCustomIdentity = (newIdentity: Identity) => { setUserData(prev => ({ ...prev, customIdentities: [...prev.customIdentities, newIdentity], identity: newIdentity, unlockedIdentityIds: [...prev.unlockedIdentityIds, newIdentity.id] })); };
    const handleAddPresetIdentity = (id: string) => { const preset = DEFAULT_IDENTITIES.find(p => p.id === id); if (preset && !userData.unlockedIdentityIds.includes(id)) setUserData(prev => ({ ...prev, unlockedIdentityIds: [...prev.unlockedIdentityIds, id], identity: preset })); };
    const handleAddGoal = (goal: Goal) => { setUserData(prev => ({ ...prev, goals: [...prev.goals, goal] })); };
    const myIdentities = useMemo(() => [...DEFAULT_IDENTITIES.filter(p => userData.unlockedIdentityIds.includes(p.id)), ...userData.customIdentities], [userData.unlockedIdentityIds, userData.customIdentities]);

    return (
        <div className={userData.theme === 'dark' ? 'dark' : ''}>
            <div className="min-h-screen bg-slate-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100 font-sans transition-colors duration-500">
                <GlobalAmbientBackground />
                <nav className="sticky top-0 z-40 backdrop-blur-md bg-white/70 dark:bg-slate-950/70 border-b border-slate-200 dark:border-white/10">
                    <div className="container mx-auto px-4 h-16 flex items-center justify-between">
                        <div className="flex items-center gap-2"><div className="w-10 h-10 rounded-xl bg-gradient-to-tr from-violet-600 to-indigo-600 flex items-center justify-center text-white"><TargetIcon className="w-6 h-6" /></div><span className="text-xl font-black">ATOMIC<span className="text-violet-500">IDENTITY</span></span></div>
                        <div className="flex items-center gap-4 md:gap-8"><button onClick={() => setActiveView('identity')} className={`text-sm font-bold ${activeView === 'identity' ? 'text-violet-500' : 'text-slate-500'}`}>Identity</button><button onClick={() => setActiveView('goals')} className={`text-sm font-bold ${activeView === 'goals' ? 'text-violet-500' : 'text-slate-500'}`}>Goals</button><button onClick={() => setActiveView('achievements')} className={`text-sm font-bold ${activeView === 'achievements' ? 'text-violet-500' : 'text-slate-500'}`}>Badges</button><button onClick={() => setUserData(p => ({ ...p, theme: p.theme === 'light' ? 'dark' : 'light' }))} className="p-2.5 rounded-xl bg-slate-100 dark:bg-white/5">{userData.theme === 'light' ? <MoonIcon className="w-5 h-5" /> : <SunIcon className="w-5 h-5" />}</button></div>
                    </div>
                </nav>
                <main className="container mx-auto px-4 pt-12">
                    {activeView === 'identity' && <IdentityBuilderView identity={userData.identity} onUpdate={handleUpdateIdentity} myIdentities={myIdentities} allPresets={DEFAULT_IDENTITIES} onSelectIdentity={handleSelectIdentity} onCreateCustom={handleCreateCustomIdentity} onAddPreset={handleAddPresetIdentity} />}
                    {activeView === 'goals' && (
                        <div className="max-w-5xl mx-auto py-12 animate-fade-in-up">
                            <div className="flex justify-between items-center mb-12"><h1 className="text-5xl font-black">Future <span className="text-violet-500">Goals</span></h1><button onClick={() => setIsAddGoalModalOpen(true)} className="px-6 py-4 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-2xl font-black text-lg flex items-center gap-2 shadow-2xl"><PlusIcon className="w-5 h-5" /> New Goal</button></div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">{userData.goals.length === 0 ? <div className="col-span-full py-32 text-center glass-card rounded-3xl border-dashed border-2"><TargetIcon className="w-12 h-12 mx-auto mb-8" /><h3 className="text-3xl font-black mb-4 uppercase">Vision is empty</h3></div> : userData.goals.map(goal => (<div key={goal.id} className="glass-card p-8 rounded-3xl border border-white/10 group"><div className="flex justify-between items-start mb-6"><div><span className="text-xs font-black uppercase text-violet-500 px-3 py-1 rounded-full bg-violet-500/10 mb-2 inline-block">{goal.category}</span><h3 className="text-2xl font-bold mt-1">{goal.title}</h3></div><TargetIcon className="w-6 h-6 text-slate-400 group-hover:text-violet-500 transition-colors" /></div><div className="space-y-4"><div className="flex justify-between text-sm font-bold"><span>Progress</span><span>{goal.progress}%</span></div><div className="h-3 rounded-full bg-slate-100 dark:bg-white/5 overflow-hidden"><div className="h-full bg-violet-500 transition-all duration-1000" style={{ width: `${goal.progress}%` }}></div></div></div></div>))}</div>
                        </div>
                    )}
                    {activeView === 'achievements' && (
                        <div className="max-w-5xl mx-auto py-12 animate-fade-in-up">
                            <h1 className="text-5xl font-black mb-16">Legacy <span className="text-amber-500">Badges</span></h1>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">{MASTER_ACHIEVEMENTS.map(a => { const isUnlocked = userData.achievements.includes(a.id); return (<div key={a.id} className={`p-10 rounded-3xl border-2 transition-all flex flex-col items-center text-center gap-6 group relative overflow-hidden ${isUnlocked ? 'glass-card border-amber-400/50 shadow-2xl scale-105' : 'opacity-40 grayscale blur-[1px]'}`}><div className={`w-24 h-24 rounded-3xl flex items-center justify-center transition-transform group-hover:rotate-12 ${isUnlocked ? 'bg-gradient-to-tr from-amber-400 to-amber-300 text-white shadow-xl' : 'bg-slate-100 dark:bg-white/5 text-slate-400'}`}><a.icon className="w-12 h-12" /></div><div><h4 className="font-black text-2xl mb-2">{a.title}</h4><p className="text-sm text-slate-500 font-medium">{a.description}</p></div>{isUnlocked && <div className="mt-2 inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-amber-400/10 text-amber-500 text-xs font-black uppercase"><CheckBadgeIcon className="w-4 h-4" /> Unlocked</div>}</div>) })}</div>
                        </div>
                    )}
                </main>
                <AddGoalModal isOpen={isAddGoalModalOpen} onClose={() => setIsAddGoalModalOpen(false)} onAdd={handleAddGoal} ai={ai} />
                {unlockedAchievement && <AchievementUnlockedModal achievement={unlockedAchievement} onClose={() => setUnlockedAchievement(null)} />}
            </div>
        </div>
    );
};

export default App;

