/**
 * STORAGE SERVICE (Data Abstraction Layer)
 * 
 * To connect a real database (like Supabase):
 * 1. Install the client: npm install @supabase/supabase-js
 * 2. Initialize it here.
 * 3. Update these methods to use 'await supabase.from(...)...'
 */

const USER_KEY = 'dailyWins_user';
const DATA_KEY = 'dailyWins_data';

export const storageService = {
    /**
     * Loads the basic user profile
     */
    async loadUser(): Promise<User | null> {
        // Simulate network delay
        await new Promise(resolve => setTimeout(resolve, 500));
        const saved = localStorage.getItem(USER_KEY);
        return saved ? JSON.parse(saved) : null;
    },

    /**
     * Saves the basic user profile
     */
    async saveUser(user: User): Promise<void> {
        localStorage.setItem(USER_KEY, JSON.stringify(user));
    },

    /**
     * Loads the full application state (goals, history, identity)
     */
    async loadUserData(): Promise<UserData | null> {
        await new Promise(resolve => setTimeout(resolve, 300));
        const saved = localStorage.getItem(DATA_KEY);
        return saved ? JSON.parse(saved) : null;
    },

    /**
     * Saves the full application state
     */
    async saveUserData(data: UserData): Promise<void> {
        // In a real database, you might only update specific tables 
        // like 'goals' or 'history' instead of the whole object.
        localStorage.setItem(DATA_KEY, JSON.stringify(data));
    },

    /**
     * Useful for clearing data if a user logs out
     */
    async clearAll(): Promise<void> {
        localStorage.removeItem(USER_KEY);
        localStorage.removeItem(DATA_KEY);
    }
};

