                                    >
                                        <div className={`p-3 rounded-xl transition-all duration-300 ${isSelected ? 'bg-white text-violet-600' : 'bg-violet-500/10 text-violet-500 group-hover:bg-violet-500 group-hover:text-white'}`}>
                                            <Icon className="w-6 h-6" />
