const OnboardingFlow = ({ user, onComplete, updateUserData, onUpdateUser, currentIdentityId, currentTheme }: { user: User, onComplete: () => void, updateUserData: (u: Partial<UserData>) => void, onUpdateUser: (n: string) => void, currentIdentityId: string, currentTheme: 'light' | 'dark' }) => {
     const [step, setStep] = useState(1);
    const nextStep = () => setStep(s => s + 1);

    const handleIdentitySelect = (id: string) => {
        const fullId = DEFAULT_IDENTITIES.find(i => i.id === id);
        if (fullId) {
            updateUserData({ identity: fullId, unlockedIdentityIds: [id] });
        }
    };

    const handleThemeSelect = (theme: 'light' | 'dark') => {
        updateUserData({ theme });
        document.documentElement.className = theme;
    };

     const StepName = () => {
        const [nameInput, setNameInput] = useState(user.name === 'Friend' ? '' : user.name);
        return (
             <div className="text-center space-y-8 animate-fade-in-up">
                <div className="mx-auto w-24 h-24 bg-gradient-to-tr from-violet-500 to-fuchsia-500 rounded-full flex items-center justify-center shadow-2xl shadow-violet-500/30">
                    <SparklesIcon className="h-12 w-12 text-white" />
                </div>
                <div>
                    <h2 className="text-4xl font-bold text-slate-900 dark:text-white">Hi, I'm DailyWins.</h2>
                    <p className="mt-4 text-xl text-slate-600 dark:text-slate-300">What should I call you?</p>
                </div>
                <input type="text" value={nameInput} onChange={(e) => setNameInput(e.target.value)} className="w-full max-w-xs mx-auto bg-transparent border-b-2 border-slate-300 dark:border-slate-600 focus:border-violet-500 text-3xl text-center font-bold text-slate-900 dark:text-white pb-2 focus:outline-none" placeholder="Your Name" autoFocus />
                <button onClick={() => { onUpdateUser(nameInput); nextStep(); }} disabled={!nameInput.trim()} className="px-8 py-4 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-full font-bold hover:scale-105 transition-transform disabled:opacity-50">Continue</button>
            </div>
        );
    };

     const StepTwo = () => (
        <div className="text-center space-y-8 animate-fade-in-up max-w-2xl">
            <h2 className="text-3xl font-bold text-slate-900 dark:text-white">The Philosophy</h2>
            <p className="text-lg text-slate-600 dark:text-slate-300">Focus on 3 wins daily: Physical, Mental, Spiritual.</p>
            <div className="flex justify-center gap-4">
                 <div className="p-4 glass-card rounded-xl"><DumbbellIcon className="w-8 h-8 text-amber-500 mx-auto"/></div>
                 <div className="p-4 glass-card rounded-xl"><BrainIcon className="w-8 h-8 text-emerald-500 mx-auto"/></div>
                 <div className="p-4 glass-card rounded-xl"><LotusIcon className="w-8 h-8 text-violet-500 mx-auto"/></div>
            </div>
            <button onClick={nextStep} className="px-8 py-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-full font-bold">Got it</button>
        </div>
    );

    const StepThree = () => {
        const mainIdentities = DEFAULT_IDENTITIES.filter(id => ['athlete', 'creator', 'scholar', 'sage'].includes(id.id));

        return (
         <div className="text-center space-y-8 animate-fade-in-up max-w-4xl">
            <h2 className="text-3xl font-bold text-slate-900 dark:text-white">Choose Focus</h2>
            <p className="text-lg text-slate-600 dark:text-slate-300">Pick one identity to start with. You can add more later.</p>
            <div className="grid grid-cols-2 gap-4">
                {mainIdentities.map(id => (
                    <button key={id.id} onClick={() => handleIdentitySelect(id.id)} className={`p-4 rounded-xl border text-left transition-all ${currentIdentityId === id.id ? 'border-violet-500 bg-violet-500/10 scale-105' : 'border-slate-200 dark:border-white/10 hover:border-violet-500/50'}`}>
                        <h3 className="font-bold text-slate-900 dark:text-white">{id.name}</h3>
                    </button>
                ))}
            </div>
            <button onClick={nextStep} className="px-8 py-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-full font-bold">Continue</button>
        </div>
        );
    };

     const StepFour = () => (
        <div className="text-center space-y-8 animate-fade-in-up">
            <h2 className="text-3xl font-bold text-slate-900 dark:text-white">Theme</h2>
            <div className="flex justify-center gap-4">
                <button onClick={() => handleThemeSelect('light')} className={`p-6 rounded-2xl border-2 ${currentTheme === 'light' ? 'border-violet-500' : 'border-transparent bg-slate-100'}`}>Light</button>
                <button onClick={() => handleThemeSelect('dark')} className={`p-6 rounded-2xl border-2 ${currentTheme === 'dark' ? 'border-violet-500' : 'border-transparent bg-slate-800 text-white'}`}>Dark</button>
            </div>
            <button onClick={onComplete} className="px-8 py-3 bg-violet-600 text-white rounded-full font-bold">Finish</button>
        </div>
    );

    return (
        <div className="fixed inset-0 z-50 bg-slate-50 dark:bg-slate-950 flex items-center justify-center p-4">
             {step === 1 && <StepName />}
             {step === 2 && <StepTwo />}
             {step === 3 && <StepThree />}
             {step === 4 && <StepFour />}
        </div>
    )
}

// --- Main App ---

export default function App() {
    const [isLoading, setIsLoading] = useState(true);
    const [user, setUser] = useState<User | null>(null);
    const [userData, setUserData] = useState<UserData | null>(null);
    const [newlyUnlockedAchievement, setNewlyUnlockedAchievement] = useState<Achievement | null>(null);

    const ai = useMemo(() => new GoogleGenAI({ apiKey: process.env.API_KEY as string }), []);

    // Initial Data Boot
    useEffect(() => {
        const boot = async () => {
            setIsLoading(true);
            try {
                const loadedUser = await storageService.loadUser();
                const loadedData = await storageService.loadUserData();

                setUser(loadedUser || { name: 'Friend' });
                setUserData(loadedData || {
                    theme: 'dark',
                    isOnboardingComplete: false,
                    identity: DEFAULT_IDENTITIES[0],
                    unlockedIdentityIds: ['athlete'], 
                    goals: [],
                    history: [],
                    streak: 0,
                    totalWins: 0,
                    customIdentities: [],
                    achievements: []
                });
            } catch (err) {
                console.error("Failed to load data", err);
            } finally {
                setIsLoading(false);
            }
        };
        boot();
    }, []);

    // Sync theme
    useEffect(() => {
        if (userData) {
            document.documentElement.className = userData.theme;
        }
    }, [userData?.theme]);

    const handleUpdateUser = async (updatedUser: User) => {
        setUser(updatedUser);
        await storageService.saveUser(updatedUser);
    };

    const handleUpdateUserData = async (newData: UserData) => {
        const unlockedIds = [...newData.achievements];
        let achievementFound = null;

        MASTER_ACHIEVEMENTS.forEach(ach => {
            if (!unlockedIds.includes(ach.id) && ach.condition(newData)) {
                unlockedIds.push(ach.id);
                achievementFound = ach;
            }
        });

        if (achievementFound) {
            setNewlyUnlockedAchievement(achievementFound);
            const updatedDataWithAch = { ...newData, achievements: unlockedIds };
            setUserData(updatedDataWithAch);
            await storageService.saveUserData(updatedDataWithAch);
        } else {
            setUserData(newData);
            await storageService.saveUserData(newData);
        }
    };

    if (isLoading) {
        return (
            <div className="fixed inset-0 bg-slate-50 dark:bg-slate-950 flex flex-col items-center justify-center z-[200]">
                <div className="w-20 h-20 border-4 border-violet-500/20 border-t-violet-500 rounded-full animate-spin mb-4"></div>
                <p className="text-slate-500 font-bold animate-pulse">Waking up Winnie...</p>
            </div>
        );
    }

    if (!userData?.isOnboardingComplete && user) {
        return (
            <div className={userData?.theme || 'dark'}>
                 <OnboardingFlow 
                    user={user}
                    onComplete={() => handleUpdateUserData({ ...userData!, isOnboardingComplete: true })}
                    updateUserData={(updates) => handleUpdateUserData({ ...userData!, ...updates })}
                    onUpdateUser={(name) => handleUpdateUser({ ...user, name })}
                    currentIdentityId={userData?.identity.id || 'athlete'}
                    currentTheme={userData?.theme || 'dark'}
                 />
            </div>
        )
    }

    return (
        <div className={userData?.theme || 'dark'}>
            {newlyUnlockedAchievement && (
                <AchievementUnlockedModal 
                    achievement={newlyUnlockedAchievement} 
                    onClose={() => setNewlyUnlockedAchievement(null)} 
                />
            )}
            {user && userData && (
                <DashboardPage 
                    userData={userData} 
                    updateUserData={handleUpdateUserData} 
                    ai={ai} 
                    user={user} 
                />
            )}
        </div>
    );
}

import Dexie, { type EntityTable } from 'dexie';
import { User, UserData, DailyData, Goal, Identity } from './App';

/**
 * DATABASE SETUP (IndexedDB via Dexie)
 * 
 * This provides a real, transactional database inside the browser.
 * It's structured with separate tables to ensure scalability as the 
 * user's journey grows over months and years.
 */

interface DBUser extends User {
    id: string; // Always 'main_user'
}

interface DBSetting {
    key: string;
    value: any;
}

class DailyWinsDB extends Dexie {
    user!: EntityTable<DBUser, 'id'>;
    history!: EntityTable<DailyData, 'date'>;
    goals!: EntityTable<Goal, 'id'>;
    settings!: EntityTable<DBSetting, 'key'>;

    constructor() {
        super('DailyWinsDB');
        this.version(1).stores({
            user: 'id',
            history: 'date',
            goals: 'id',
            settings: 'key'
        });
    }
}

const db = new DailyWinsDB();

// Migration helper to pull from localStorage to IndexedDB on first run
const migrateFromLocalStorage = async () => {
    const hasMigrated = localStorage.getItem('db_migrated');
    if (hasMigrated) return;

    try {
        const legacyUser = localStorage.getItem('dailyWins_user');
        if (legacyUser) {
            await db.user.put({ ...JSON.parse(legacyUser), id: 'main_user' });
        }

        const legacyData = localStorage.getItem('dailyWins_data');
        if (legacyData) {
            const data: UserData = JSON.parse(legacyData);

            // Save global settings
            await db.settings.put({ key: 'theme', value: data.theme });
            await db.settings.put({ key: 'isOnboardingComplete', value: data.isOnboardingComplete });
            await db.settings.put({ key: 'activeIdentity', value: data.identity });
            await db.settings.put({ key: 'unlockedIdentityIds', value: data.unlockedIdentityIds });
            await db.settings.put({ key: 'streak', value: data.streak });
            await db.settings.put({ key: 'totalWins', value: data.totalWins });
            await db.settings.put({ key: 'customIdentities', value: data.customIdentities });
            await db.settings.put({ key: 'achievements', value: data.achievements });
            await db.settings.put({ key: 'dailyAffirmation', value: data.dailyAffirmation });
            await db.settings.put({ key: 'todayDraft', value: data.todayDraft });

            // Bulk save history and goals
            if (data.history?.length) await db.history.bulkPut(data.history);
            if (data.goals?.length) await db.goals.bulkPut(data.goals);
        }

        localStorage.setItem('db_migrated', 'true');
    } catch (e) {
        console.error("Migration failed", e);
    }
};

export const storageService = {
    /**
     * Initializes the DB and handles legacy data migration
     */
    async init(): Promise<void> {
        await migrateFromLocalStorage();
    },

    /**
     * Loads the basic user profile
     */
    async loadUser(): Promise<User | null> {
        const profile = await db.user.get('main_user');
        return profile ? { name: profile.name } : null;
    },

    /**
     * Saves the basic user profile
     */
    async saveUser(user: User): Promise<void> {
        await db.user.put({ ...user, id: 'main_user' });
    },

    /**
     * Reconstructs the full UserData object from multiple tables
     */
    async loadUserData(): Promise<UserData | null> {
        const settingsList = await db.settings.toArray();
        const settings: Record<string, any> = {};
        settingsList.forEach(s => settings[s.key] = s.value);

        if (Object.keys(settings).length === 0) return null;

        const history = await db.history.toArray();
        const goals = await db.goals.toArray();

        return {
            theme: settings.theme || 'dark',
            isOnboardingComplete: settings.isOnboardingComplete,
            identity: settings.activeIdentity,
            unlockedIdentityIds: settings.unlockedIdentityIds || [],
            goals: goals,
            history: history,
            todayDraft: settings.todayDraft,
            streak: settings.streak || 0,
            totalWins: settings.totalWins || 0,
            customIdentities: settings.customIdentities || [],
            achievements: settings.achievements || [],
            dailyAffirmation: settings.dailyAffirmation
        };
    },

    /**
     * Saves the full application state into relational tables
     */
    async saveUserData(data: UserData): Promise<void> {
        // Use a transaction for atomic updates across multiple tables
        await db.transaction('rw', db.settings, db.history, db.goals, async () => {
            // Update individual history entries
            if (data.history?.length) {
                await db.history.bulkPut(data.history);
            }

            // Update individual goal entries
            if (data.goals?.length) {
                await db.goals.clear(); // Ensure sync for deletions
                await db.goals.bulkPut(data.goals);
            }

            // Update flat settings
            await db.settings.bulkPut([
                { key: 'theme', value: data.theme },
                { key: 'isOnboardingComplete', value: data.isOnboardingComplete },
                { key: 'activeIdentity', value: data.identity },
                { key: 'unlockedIdentityIds', value: data.unlockedIdentityIds },
                { key: 'streak', value: data.streak },
                { key: 'totalWins', value: data.totalWins },
                { key: 'customIdentities', value: data.customIdentities },
                { key: 'achievements', value: data.achievements },
                { key: 'dailyAffirmation', value: data.dailyAffirmation },
                { key: 'todayDraft', value: data.todayDraft }
            ]);
        });
    },

    /**
     * Deletes the entire local database
     */
    async clearAll(): Promise<void> {
        await db.delete();
        localStorage.removeItem('db_migrated');
        window.location.reload();
    }
};

