const GoalAdvisorChatbot = ({ ai, onSuggestGoal }: { ai: GoogleGenAI, onSuggestGoal: (goal: Goal) => void }) => {
    const [messages, setMessages] = useState<{role: 'user'|'model', text: string, goalData?: any}[]>([
        { role: 'model', text: "Hi! I'm Winnie, your goal coach. Tell me what you want to achieve." }
    ]);
    const [input, setInput] = useState('');
    const [isThinking, setIsThinking] = useState(false);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => { if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight; }, [messages]);

    const handleSend = async () => {
        if (!input.trim()) return;
        const userMsg = input;
        setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
        setInput('');
        setIsThinking(true);
        try {
            const chat = ai.chats.create({
                model: 'gemini-3-flash-preview',
                config: { systemInstruction: "You are a helpful goal setting coach. If user is clear, suggest a goal in JSON format: { 'suggested_goal': { 'title': '...', 'category': 'Health|Business|Personal|Financial' } }." }
            });
            const result = await chat.sendMessage({ message: userMsg });
            let goalData = null;
            let displayMsg = result.text || "";
            try {
                const jsonMatch = displayMsg.match(/\{[\s\S]*\}/);
                if (jsonMatch) {
                    const parsed = JSON.parse(jsonMatch[0]);
                    if (parsed.suggested_goal) {
                        goalData = parsed.suggested_goal;
                        displayMsg = "I've structured a goal based on our talk:";
                    }
                }
            } catch(e) {}
            setMessages(prev => [...prev, { role: 'model', text: displayMsg, goalData }]);
        } catch (error) {
            setMessages(prev => [...prev, { role: 'model', text: "I'm having trouble thinking right now." }]);
        } finally {
            setIsThinking(false);
        }
    };

    return (
        <div className="flex flex-col h-[500px] glass-card rounded-2xl overflow-hidden">
            <div className="p-4 border-b border-white/10 font-bold bg-white/5">Winnie AI Coach</div>
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
                {messages.map((m, i) => (
                    <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[85%] rounded-2xl p-3 ${m.role === 'user' ? 'bg-violet-600 text-white' : 'bg-white/10'}`}>
                            <p className="text-sm">{m.text}</p>
                            {m.goalData && (
                                <button onClick={() => onSuggestGoal({...m.goalData, id: Date.now().toString(), progress: 0, milestones: []})} className="mt-2 w-full py-2 bg-white text-slate-900 rounded-lg text-xs font-bold">Add Goal</button>
                            )}
                        </div>
                    </div>
                ))}
                {isThinking && <div className="text-xs text-slate-500 animate-pulse">Winnie is thinking...</div>}
            </div>
            <div className="p-4 flex gap-2">
                <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSend()} className="flex-1 bg-transparent border-b border-white/20 outline-none p-1" placeholder="Ask Winnie..." />
                <button onClick={handleSend} className="p-2 bg-violet-600 rounded-lg"><SendIcon className="w-4 h-4 text-white"/></button>
            </div>
        </div>
    );
};

const DashboardPage = ({ userData, updateUserData, ai, user }: any) => {
    const [view, setView] = useState('today');
    const todayStr = new Date().toISOString().split('T')[0];
    const todayData = useMemo(() => {
        const saved = userData.history.find((d: any) => d.date === todayStr);
        if (saved) return saved;
        return userData.todayDraft || { date: todayStr, wins: [{ id: '1', category: 'physical', text: '', completed: false }, { id: '2', category: 'mental', text: '', completed: false }, { id: '3', category: 'spiritual', text: '', completed: false }], reflection: '', mood: 0 };
    }, [userData.history, userData.todayDraft, todayStr]);

    const handleWinUpdate = (i: number, text: string) => {
        const newWins = [...todayData.wins];
        newWins[i].text = text;
        updateUserData({ ...userData, todayDraft: { ...todayData, wins: newWins } });
    };

    const handleToggleWin = (i: number) => {
        const newWins = [...todayData.wins];
        newWins[i].completed = !newWins[i].completed;
        updateUserData({ ...userData, todayDraft: { ...todayData, wins: newWins } });
    };

    return (
        <div className="flex flex-col h-screen">
            <header className="h-16 flex items-center justify-between px-6 border-b border-white/5 backdrop-blur-md">
                <span className="font-bold text-xl">DailyWins</span>
                <span className="text-sm font-bold opacity-70">{userData.streak}🔥</span>
            </header>
            <main className="flex-1 overflow-y-auto p-6 pb-24">
                {view === 'today' && (
                    <div className="max-w-xl mx-auto space-y-8 animate-fade-in-up">
                        <h1 className="text-4xl font-black">Win the day, {user.name}</h1>
                        <div className="space-y-4">
                            {todayData.wins.map((win: any, i: number) => (
                                <div key={win.id} className={`glass-card p-6 rounded-3xl flex items-center gap-4 ${win.completed ? 'opacity-50' : ''}`}>
                                    <div className="flex-1">
                                        <input value={win.text} onChange={e => handleWinUpdate(i, e.target.value)} placeholder={`Your ${win.category} win...`} className="w-full bg-transparent outline-none text-lg font-medium" />
                                    </div>
                                    <button onClick={() => handleToggleWin(i)} className={`w-10 h-10 rounded-full border-2 flex items-center justify-center ${win.completed ? 'bg-green-500 border-green-500' : 'border-white/20'}`}>
                                        {win.completed ? <CheckCircleIconSolid className="w-6 h-6 text-white"/> : <PlusIcon className="w-5 h-5"/>}
                                    </button>
                                </div>
                            ))}
                        </div>
                        <button onClick={() => updateUserData({...userData, history: [...userData.history, todayData], totalWins: userData.totalWins + todayData.wins.filter((w:any)=>w.completed).length, streak: userData.streak + 1})} className="w-full py-4 bg-violet-600 rounded-2xl font-bold">Complete Day</button>
                    </div>
                )}
                {view === 'goals' && (
                    <div className="max-w-4xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="space-y-4">
                            <h2 className="text-3xl font-bold">My Vision</h2>
                            {userData.goals.map((g: any) => (
                                <div key={g.id} className="glass-card p-6 rounded-3xl">
                                    <div className="text-xs font-bold uppercase opacity-50 mb-1">{g.category}</div>
                                    <div className="text-xl font-bold">{g.title}</div>
                                </div>
                            ))}
                        </div>
                        <GoalAdvisorChatbot ai={ai} onSuggestGoal={(g) => updateUserData({...userData, goals: [...userData.goals, g]})} />
                    </div>
                )}
                {view === 'profile' && (
                    <div className="max-w-xl mx-auto space-y-8">
                        <div className="glass-card p-8 rounded-3xl text-center">
                            <div className="text-5xl font-black mb-2">{userData.totalWins}</div>
                            <div className="text-sm font-bold uppercase opacity-50">Lifetime Wins</div>
                        </div>
                        <button onClick={() => storageService.clearAll()} className="w-full py-4 text-red-500 font-bold">Clear All Data</button>
                    </div>
                )}
            </main>
            <nav className="fixed bottom-0 left-0 right-0 h-20 glass-card border-t border-white/10 flex justify-around items-center">
                <button onClick={() => setView('today')} className={`p-4 ${view === 'today' ? 'text-violet-500' : 'opacity-40'}`}><CheckCircleIcon className="w-6 h-6"/></button>
                <button onClick={() => setView('goals')} className={`p-4 ${view === 'goals' ? 'text-violet-500' : 'opacity-40'}`}><TargetIcon className="w-6 h-6"/></button>
                <button onClick={() => setView('profile')} className={`p-4 ${view === 'profile' ? 'text-violet-500' : 'opacity-40'}`}><UserCircleIcon className="w-6 h-6"/></button>
            </nav>
        </div>
    );
};

export default function App() {
    const [isLoading, setIsLoading] = useState(true);
    const [user, setUser] = useState<User | null>(null);
    const [userData, setUserData] = useState<UserData | null>(null);
    const [achievement, setAchievement] = useState<Achievement | null>(null);

    const ai = useMemo(() => new GoogleGenAI({ apiKey: process.env.API_KEY as string }), []);

    useEffect(() => {
        (async () => {
            await storageService.init();
            const u = await storageService.loadUser();
            const d = await storageService.loadUserData();
            setUser(u || { name: 'Friend' });
            setUserData(d || { theme: 'dark', isOnboardingComplete: true, identity: DEFAULT_IDENTITIES[0], unlockedIdentityIds: ['athlete'], goals: [], history: [], streak: 0, totalWins: 0, customIdentities: [], achievements: [] });
            setIsLoading(false);
        })();
    }, []);

    const handleUpdate = async (newData: UserData) => {
        const newlyUnlocked = MASTER_ACHIEVEMENTS.find(ach => !newData.achievements.includes(ach.id) && ach.condition(newData));
        if (newlyUnlocked) {
            newData.achievements.push(newlyUnlocked.id);
            setAchievement(newlyUnlocked);
        }
        setUserData(newData);
        await storageService.saveUserData(newData);
    };

    if (isLoading) return <div className="h-screen flex items-center justify-center font-bold animate-pulse">Loading...</div>;

    return (
        <div className={userData?.theme === 'dark' ? 'dark text-white' : 'text-slate-900'}>
            {achievement && <AchievementUnlockedModal achievement={achievement} onClose={() => setAchievement(null)} />}
            {user && userData && <DashboardPage userData={userData} updateUserData={handleUpdate} ai={ai} user={user} />}
        </div>
    );
}

import { Dexie, type EntityTable } from 'dexie';
import { User, UserData, DailyData, Goal } from './App';

interface DBUser extends User {
    id: string; 
}

interface DBSetting {
    key: string;
    value: any;
}

class DailyWinsDB extends Dexie {
    user!: EntityTable<DBUser, 'id'>;
    history!: EntityTable<DailyData, 'date'>;
    goals!: EntityTable<Goal, 'id'>;
    settings!: EntityTable<DBSetting, 'key'>;

    constructor() {
        super('DailyWinsDB');
        this.version(1).stores({
            user: 'id',
            history: 'date',
            goals: 'id',
            settings: 'key'
        });
    }
}

const db = new DailyWinsDB();

export const storageService = {
    async init(): Promise<void> {
        // Migration can happen here if needed in the future
    },

    async loadUser(): Promise<User | null> {
        const profile = await db.user.get('main_user');
        return profile ? { name: profile.name } : null;
    },

    async saveUser(user: User): Promise<void> {
        await db.user.put({ ...user, id: 'main_user' });
    },

    async loadUserData(): Promise<UserData | null> {
        const settingsList = await db.settings.toArray();
        const settings: Record<string, any> = {};
        settingsList.forEach(s => settings[s.key] = s.value);

        if (Object.keys(settings).length === 0) return null;

        const history = await db.history.toArray();
        const goals = await db.goals.toArray();

        return {
            theme: settings.theme || 'dark',
            isOnboardingComplete: settings.isOnboardingComplete,
            identity: settings.activeIdentity,
            unlockedIdentityIds: settings.unlockedIdentityIds || [],
            goals: goals,
            history: history,
            todayDraft: settings.todayDraft,
            streak: settings.streak || 0,
            totalWins: settings.totalWins || 0,
            customIdentities: settings.customIdentities || [],
            achievements: settings.achievements || [],
            dailyAffirmation: settings.dailyAffirmation
        };
    },

    async saveUserData(data: UserData): Promise<void> {
        await db.transaction('rw', [db.settings, db.history, db.goals], async () => {
            if (data.history?.length) {
                await db.history.bulkPut(data.history);
            }
            if (data.goals?.length) {
                await db.goals.clear(); 
                await db.goals.bulkPut(data.goals);
            }
            await db.settings.bulkPut([
                { key: 'theme', value: data.theme },
                { key: 'isOnboardingComplete', value: data.isOnboardingComplete },
                { key: 'activeIdentity', value: data.identity },
                { key: 'unlockedIdentityIds', value: data.unlockedIdentityIds },
                { key: 'streak', value: data.streak },
                { key: 'totalWins', value: data.totalWins },
                { key: 'customIdentities', value: data.customIdentities },
                { key: 'achievements', value: data.achievements },
                { key: 'dailyAffirmation', value: data.dailyAffirmation },
                { key: 'todayDraft', value: data.todayDraft }
            ]);
        });
    },

    async clearAll(): Promise<void> {
        await db.delete();
        window.location.reload();
    }
};

import { Dexie, type EntityTable } from 'dexie';
import { User, UserData, DailyData, Goal } from './App';

interface DBUser extends User {
    id: string; 
}

interface DBSetting {
    key: string;
    value: any;
}

class DailyWinsDB extends Dexie {
    user!: EntityTable<DBUser, 'id'>;
    history!: EntityTable<DailyData, 'date'>;
    goals!: EntityTable<Goal, 'id'>;
    settings!: EntityTable<DBSetting, 'key'>;

    constructor() {
        super('DailyWinsDB');
        // Fix: Use 'any' cast to bypass missing property error for 'version' on the class instance.
        // This is necessary when the environment's Dexie type definitions are incomplete or misconfigured.
        (this as any).version(1).stores({
            user: 'id',
            history: 'date',
            goals: 'id',
            settings: 'key'
        });
    }
}

const db = new DailyWinsDB();

export const storageService = {
    async init(): Promise<void> {
        // Migration can happen here if needed in the future
    },

    async loadUser(): Promise<User | null> {
        const profile = await db.user.get('main_user');
        return profile ? { name: profile.name } : null;
    },

    async saveUser(user: User): Promise<void> {
        await db.user.put({ ...user, id: 'main_user' });
    },

    async loadUserData(): Promise<UserData | null> {
        const settingsList = await db.settings.toArray();
        const settings: Record<string, any> = {};
        settingsList.forEach(s => settings[s.key] = s.value);

        if (Object.keys(settings).length === 0) return null;

        const history = await db.history.toArray();
        const goals = await db.goals.toArray();

        return {
            theme: settings.theme || 'dark',
            isOnboardingComplete: settings.isOnboardingComplete,
            identity: settings.activeIdentity,
            unlockedIdentityIds: settings.unlockedIdentityIds || [],
            goals: goals,
            history: history,
            todayDraft: settings.todayDraft,
            streak: settings.streak || 0,
            totalWins: settings.totalWins || 0,
            customIdentities: settings.customIdentities || [],
            achievements: settings.achievements || [],
            dailyAffirmation: settings.dailyAffirmation
        };
    },

    async saveUserData(data: UserData): Promise<void> {
        // Fix: Use 'any' cast to bypass missing property error for 'transaction' on the Dexie instance.
        await (db as any).transaction('rw', [db.settings, db.history, db.goals], async () => {
            if (data.history?.length) {
                await db.history.bulkPut(data.history);
            }
            if (data.goals?.length) {
                await db.goals.clear(); 
                await db.goals.bulkPut(data.goals);
            }
            await db.settings.bulkPut([
                { key: 'theme', value: data.theme },
                { key: 'isOnboardingComplete', value: data.isOnboardingComplete },
                { key: 'activeIdentity', value: data.identity },
                { key: 'unlockedIdentityIds', value: data.unlockedIdentityIds },
                { key: 'streak', value: data.streak },
                { key: 'totalWins', value: data.totalWins },
                { key: 'customIdentities', value: data.customIdentities },
                { key: 'achievements', value: data.achievements },
                { key: 'dailyAffirmation', value: data.dailyAffirmation },
                { key: 'todayDraft', value: data.todayDraft }
            ]);
        });
    },

    async clearAll(): Promise<void> {
        // Fix: Use 'any' cast to bypass missing property error for 'delete' on the Dexie instance.
        await (db as any).delete();
        window.location.reload();
    }
};
